$log = @()

function Read-Telnet($client, $ms=2500){
$sr = New-Object System.IO.StreamReader($client.GetStream())
$sb = New-Object System.Text.StringBuilder
$sw = [System.Diagnostics.Stopwatch]::StartNew()
while ($sw.ElapsedMilliseconds -lt $ms){
while ($client.Available -gt 0) {
$ch = $sr.Read()
if ($ch -lt 0) { return $sb.ToString() }
[void]$sb.Append([char]$ch)
}
Start-Sleep -Milliseconds 50
}
return $sb.ToString()
